import { decodeSencode } from '@sudoku/sencode';
import { generateSudoku } from '@sudoku/sudoku';
import { createGame, createSudoku } from '../../domain/index.js';
import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { gameSession } from './stores/grid';
import { timer } from './stores/timer';
import { hints } from './stores/hints';

/**
 * 功能：根据题面初始化一局新的前端游戏会话。
 * 上下文：此函数在开始新局或加载分享题目时被调用，是 UI 层进入领域层的主要入口。
 * 逻辑：这里直接替换整个 session，而不是在旧 session 上局部修改，
 * 这样既能重置领域层历史，也能一并清理不该跨题目保留的 UI 辅助状态。
 *
 * @param {number[][]} puzzleGrid
 */
function startSession(puzzleGrid) {
	const puzzle = createSudoku(puzzleGrid);
	const sessionGame = createGame({ sudoku: puzzle });

	gameSession.loadSession({
		puzzle,
		game: sessionGame,
	});

	cursor.reset();
	timer.reset();
	hints.reset();
}

/**
 * 功能：使用随机生成的题面开始一局新游戏。
 * 上下文：此函数通常由欢迎弹窗或难度选择菜单触发。
 *
 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} diff - Difficulty
 */
export function startNew(diff) {
	difficulty.set(diff);
	startSession(generateSudoku(diff));

	location.hash = '';
}

/**
 * 功能：使用分享码解析出的题面开始一局新游戏。
 * 上下文：此函数用于加载自定义题目或朋友分享的题目。
 *
 * @param {string} sencode - Sencode to decode
 */
export function startCustom(sencode) {
	difficulty.setCustom();
	startSession(decodeSencode(sencode));
}

/**
 * 功能：执行撤销操作。
 * 上下文：此函数由操作栏按钮调用，底层委托给领域层 Game 的 undo()。
 *
 * @returns {boolean}
 */
export function undoGame() {
	return gameSession.undo();
}

/**
 * 功能：执行重做操作。
 * 上下文：此函数由操作栏按钮调用，底层委托给领域层 Game 的 redo()。
 *
 * @returns {boolean}
 */
export function redoGame() {
	return gameSession.redo();
}

/**
 * 功能：查询当前是否允许撤销。
 * 上下文：此函数主要用于按钮状态控制，也可供其他 UI 逻辑复用。
 *
 * @returns {boolean}
 */
export function canUndo() {
	return gameSession.canUndo();
}

/**
 * 功能：查询当前是否允许重做。
 * 上下文：此函数主要用于按钮状态控制，也可供其他 UI 逻辑复用。
 *
 * @returns {boolean}
 */
export function canRedo() {
	return gameSession.canRedo();
}

/**
 * 功能：暂停当前游戏。
 * 上下文：此函数在弹窗打开、菜单展开等需要冻结交互的场景中被调用。
 */
export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

/**
 * 功能：恢复当前游戏。
 * 上下文：此函数在弹窗关闭或暂停结束后调用，用于重新开启计时和交互。
 */
export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

export default {
	startNew,
	startCustom,
	undo: undoGame,
	redo: redoGame,
	canUndo,
	canRedo,
	pause: pauseGame,
	resume: resumeGame
};
